function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const adj = new Array(n).fill(0).map(() => []);
    for (const [u, v, cost] of edges) {
        adj[u].push({ node: v, cost });
    }

    const bestMin = new Array(n).fill(-Infinity);
    bestMin[0] = Infinity;

    class PriorityQueue {
        private heap: [number, number, number][]; // [priority, totalCost, node]

        constructor() {
            this.heap = [];
        }

        push(value: [number, number, number]) {
            this.heap.push(value);
            let i = this.heap.length - 1;
            while (i > 0) {
                const parent = Math.floor((i - 1) / 2);
                if (this.heap[i][0] >= this.heap[parent][0]) {
                    [this.heap[i], this.heap[parent]] = [this.heap[parent], this.heap[i]];
                    i = parent;
                } else {
                    break;
                }
            }
        }

        pop(): [number, number, number] | null {
            if (this.heap.length === 0) return null;
            const val = this.heap[0];
            this.heap[0] = this.heap[this.heap.length - 1];
            this.heap.pop();
            let i = 0;
            while (true) {
                const left = 2 * i + 1;
                const right = 2 * i + 2;
                let smallest = i;
                if (left < this.heap.length && this.heap[left][0] < this.heap[smallest][0]) {
                    smallest = left;
                }
                if (right < this.heap.length && this.heap[right][0] < this.heap[smallest][0]) {
                    smallest = right;
                }
                if (smallest === i) break;
                [this.heap[i], this.heap[smallest]] = [this.heap[smallest], this.heap[i]];
                i = smallest;
            }
            return val;
        }

        isEmpty(): boolean {
            return this.heap.length === 0;
        }
    }

    const pq = new PriorityQueue();
    pq.push([ -Infinity, 0, 0 ]);

    while (!pq.isEmpty()) {
        const [negCurrentMin, totalCost, u] = pq.pop() as [number, number, number];
        const currentMin = -negCurrentMin;

        if (u === n - 1) {
            return currentMin;
        }

        if (bestMin[u] > currentMin) {
            continue;
        }

        for (const edge of adj[u]) {
            const v = edge.node;
            const cost = edge.cost;

            if (!online[v]) {
                continue;
            }

            const newTotalCost = totalCost + cost;
            if (newTotalCost > k) {
                continue;
            }

            const newMin = Math.min(currentMin, cost);
            if (newMin > bestMin[v]) {
                bestMin[v] = newMin;
                pq.push([ -newMin, newTotalCost, v ]);
            }
        }
    }

    return -1;
}

